const initListener=async()=>{const e=document.getElementById("menu-toggle"),t=document.getElementById("nav-links");e.addEventListener("click",()=>{const n=t.classList.toggle("active");e.setAttribute("aria-expanded",String(n))}),document.querySelectorAll(".nav-links a, .floating-rsvp").forEach(n=>{n.addEventListener("click",a=>{a.preventDefault(),t.classList.remove("active"),e.setAttribute("aria-expanded","false");const s=n.getAttribute("href"),o=document.querySelector(s);o&&o.scrollIntoView({behavior:"smooth",block:"start"})})}),window.addEventListener("scroll",()=>{const e=document.querySelector(".navbar");window.scrollY>50?(e.style.background="rgba(247,248,246,0.96)",e.style.boxShadow="0 4px 20px rgba(0,0,0,0.05)"):(e.style.background="rgba(247,248,246,0.90)",e.style.boxShadow="none")});const n=new IntersectionObserver(e=>{e.forEach(e=>{const t=e.target.querySelector("iframe");t&&(e.isIntersecting?t.style.display="block":t.style.display="none")})},{root:null,threshold:.2,rootMargin:"200px 0px"});document.querySelectorAll(".iframe-limit").forEach(e=>n.observe(e));const a=document.querySelectorAll(".map-btn"),s=document.getElementById("ceremony-map"),o=document.getElementById("reception-map");a.forEach(e=>{e.addEventListener("click",()=>{const t=e.dataset.map;a.forEach(e=>e.classList.remove("active")),e.classList.add("active"),s.classList.remove("active-map"),o.classList.remove("active-map"),"ceremony"===t?s.classList.add("active-map"):o.classList.add("active-map")})}),document.querySelectorAll(".details-qr img").forEach(e=>{const t=e.closest(".details-qr");e.addEventListener("load",()=>t.classList.remove("hidden")),e.addEventListener("error",()=>t.classList.add("hidden"))})};"loading"===document.readyState?document.addEventListener("DOMContentLoaded",initListener):initListener();